import React from "react";
import { Plus, Target } from "lucide-react";

export default function GoalsScreen({ openScreen, goals = [] }) {
  return (
    <div className="p-6 pb-24 animate-in fade-in duration-300">
      {/* Header */}
      <div className="flex justify-between items-center mb-6 pt-4">
        <h2 className="text-2xl font-bold text-gray-900">Your Goals</h2>
        <button
          onClick={() => openScreen("CreateGoalScreen")}
          className="w-12 h-12 rounded-2xl bg-emerald-50 text-[#00875A] flex items-center justify-center"
        >
          <Plus size={24} strokeWidth={3} />
        </button>
      </div>

      {/* Goals List */}
      <div className="space-y-4">
        {goals.length > 0 ? (
          goals.map((goal) => (
            <div
              key={goal.id}
              onClick={() => openScreen("GoalDetailsScreen", goal)}
              className="bg-white p-5 rounded-[2rem] border border-gray-100 shadow-sm cursor-pointer active:scale-[0.98] transition"
            >
              <div className="flex items-center gap-4 mb-4">
                <div className="w-14 h-14 bg-gray-50 rounded-2xl flex items-center justify-center text-3xl shadow-inner">
                  {goal.icon}
                </div>
                <div className="flex-1">
                  <h3 className="font-black text-gray-800">{goal.title}</h3>
                  <p className="text-xs text-gray-400 font-bold uppercase tracking-wider">
                    ${goal.current.toLocaleString()} / ${goal.target.toLocaleString()}
                  </p>
                </div>
                <div className="text-right">
                  <p className="text-[#00875A] font-black text-lg">
                    {Math.round((goal.current / goal.target) * 100)}%
                  </p>
                </div>
              </div>
              <div className="h-2.5 bg-gray-100 rounded-full overflow-hidden">
                <div
                  className={`${goal.color} h-full rounded-full transition-all duration-1000 ease-out`}
                  style={{ width: `${(goal.current / goal.target) * 100}%` }}
                />
              </div>
            </div>
          ))
        ) : (
          <p className="text-gray-400 font-bold">No goals yet.</p>
        )}

        {/* Add New Target Card */}
        <div
          onClick={() => openScreen("CreateGoalScreen")}
          className="p-8 border-2 border-dashed border-gray-100 rounded-[2rem] flex flex-col items-center justify-center opacity-50 mt-4 cursor-pointer hover:opacity-80 transition"
        >
          <Target className="text-gray-300 mb-2" size={32} />
          <p className="font-bold text-gray-400">Add a new target</p>
        </div>
      </div>
    </div>
  );
}
